import{_ as s,o as e,c as n,ag as p}from"./chunks/framework.ePeAWSvT.js";const m=JSON.parse('{"title":"设计理念","description":"","frontmatter":{},"headers":[],"relativePath":"memory-bench/server/design.md","filePath":"memory-bench/server/design.md"}'),i={name:"memory-bench/server/design.md"};function t(l,a,o,r,c,d){return e(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="设计理念" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念" aria-label="Permalink to &quot;设计理念&quot;">​</a></h1><p>Memory Bench Server 是 memory_bench 子项目的核心服务，为 AI 角色对话提供<strong>记忆增强</strong>能力。</p><h2 id="🎯-核心问题" tabindex="-1">🎯 核心问题 <a class="header-anchor" href="#🎯-核心问题" aria-label="Permalink to &quot;🎯 核心问题&quot;">​</a></h2><blockquote><p>AI 聊天机器人普遍存在&quot;金鱼记忆&quot;问题——每次对话都从零开始，不记得之前说过什么。</p></blockquote><p>Memory Bench Server 的目标是解决这个问题：让 AI 角色能<strong>真正记住</strong>与用户的交互，并将记忆结构化为可查询的知识图谱。</p><hr><h2 id="📐-架构定位-记忆后端-不是透明代理" tabindex="-1">📐 架构定位：记忆后端，不是透明代理 <a class="header-anchor" href="#📐-架构定位-记忆后端-不是透明代理" aria-label="Permalink to &quot;📐 架构定位：记忆后端，不是透明代理&quot;">​</a></h2><p>Memory Bench Server 是一个<strong>记忆后端服务</strong>，职责是存储、检索记忆，以及维护 Neo4j 知识图谱。它不参与 LLM 调用，也不管理对话历史——这些由 <code>AgentCore</code> 负责。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AgentCore（主链路）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── on_before_turn → POST /memory/search   ← 搜索相关记忆，注入 context</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── run_turn() → LLM 生成回复</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └── on_after_turn → POST /memory/add      ← 写入本轮对话，触发图谱管线</span></span></code></pre></div><p>调用方永远是 <code>MemoryPlugin</code>（AgentCore 的 hook 插件），identity（<code>user_id</code>/<code>agent_id</code>）由 Profile 的 <code>[plugins.memory]</code> 决定，server 端不持有固定 identity。</p><hr><h2 id="🧠-记忆架构" tabindex="-1">🧠 记忆架构 <a class="header-anchor" href="#🧠-记忆架构" aria-label="Permalink to &quot;🧠 记忆架构&quot;">​</a></h2><h3 id="mem0-记忆的存储与检索" tabindex="-1">mem0：记忆的存储与检索 <a class="header-anchor" href="#mem0-记忆的存储与检索" aria-label="Permalink to &quot;mem0：记忆的存储与检索&quot;">​</a></h3><p><a href="https://github.com/mem0ai/mem0" target="_blank" rel="noreferrer">mem0</a> 负责从对话中<strong>自动提取</strong>和<strong>语义检索</strong>记忆：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /memory/add（user_text + assistant_text + user_id + agent_id）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>mem0.add() → 自动提取记忆要点 → 存入 Qdrant</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>claim_extractor.py → LLM 提取 claim / entity</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>graph_writer.py → Cypher MERGE → Neo4j</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /memory/search（query + user_id + agent_id）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>mem0.search() → 语义检索 → 返回相关记忆列表</span></span></code></pre></div><p><strong>关键设计决策</strong>：</p><ul><li>写入只记录 <code>user_text</code> + <code>assistant_text</code>，不写入工具调用中间步骤</li><li>事实提取使用自定义 prompt，区分 <code>[User]</code> 和 <code>[Agent]</code> 前缀</li><li><code>user_id</code> / <code>agent_id</code> 来自请求参数，server 端不 fallback——缺失直接报错</li></ul><h3 id="neo4j-记忆的图谱化" tabindex="-1">Neo4j：记忆的图谱化 <a class="header-anchor" href="#neo4j-记忆的图谱化" aria-label="Permalink to &quot;Neo4j：记忆的图谱化&quot;">​</a></h3><p>每条记忆通过实时图谱管线被结构化为知识图谱节点：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mem0.add() 返回结果</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>claim_extractor.py → 提取 claim / entity</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>neo4j_queries.py → Cypher MERGE 写入 Neo4j</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>MemoryItem 节点 → 关联 Character / Scene / Conversation</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">图谱管线是可选的（\`--enable-graph\`），不影响基础搜索和写入功能。</p><p></p></div><h3 id="多-agent-共存" tabindex="-1">多 Agent 共存 <a class="header-anchor" href="#多-agent-共存" aria-label="Permalink to &quot;多 Agent 共存&quot;">​</a></h3><p>不同 Agent（如 elaina、congyin）共用同一个 Neo4j 图，通过 <code>agent_id</code> 隔离各自的记忆节点。mem0 的向量搜索以 <code>(user_id, agent_id)</code> 为命名空间，天然隔离。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Neo4j 图</span></span>
<span class="line"><span>  ├── (char:elaina) ← elaina 的 MemoryItem 节点</span></span>
<span class="line"><span>  ├── (char:congyin) ← congyin 的 MemoryItem 节点</span></span>
<span class="line"><span>  └── (char:xnne) ← 用户节点，与两个 agent 均有关联边</span></span></code></pre></div><hr><h2 id="🔌-与-src-lab-的关系" tabindex="-1">🔌 与 <code>src/lab</code> 的关系 <a class="header-anchor" href="#🔌-与-src-lab-的关系" aria-label="Permalink to &quot;🔌 与 \`src/lab\` 的关系&quot;">​</a></h2><p><code>src/lab</code>（主项目）通过 <code>MemoryPlugin</code> 与 Memory Bench Server 交互：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Profile（elaina.toml / congyin.toml）</span></span>
<span class="line"><span>  [plugins.memory]</span></span>
<span class="line"><span>    user_id = &quot;xnne&quot;</span></span>
<span class="line"><span>    agent_id = &quot;elaina&quot;      ← 记忆归属的唯一来源</span></span>
<span class="line"><span>    base_url = &quot;http://localhost:12393&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AgentCore</span></span>
<span class="line"><span>  ├── MemoryPlugin.on_before_turn → /memory/search（带 agent_id）</span></span>
<span class="line"><span>  └── MemoryPlugin.on_after_turn  → /memory/add（带 agent_id）</span></span></code></pre></div><p><strong>约定</strong>：</p><ul><li>Memory Bench Server 只做记忆存取，不感知 AgentCore 的 LLM 调用或工具调用</li><li><code>agent_id</code> 由 Plugin 从 Profile 读取后显式传入，server 不持有默认值</li><li>配置隔离：memory_bench 的连接配置来自 <code>.env.benchmark</code>，不读取 <code>lab.toml</code></li></ul><hr><h2 id="🛠️-chat-server-独立调试工具" tabindex="-1">🛠️ chat_server：独立调试工具 <a class="header-anchor" href="#🛠️-chat-server-独立调试工具" aria-label="Permalink to &quot;🛠️ chat_server：独立调试工具&quot;">​</a></h2><p><code>chat_server.py</code> 是一个<strong>独立的命令行调试工具</strong>，不在主链路中。它直接起一个带记忆的 REPL 对话，用于测试特定 <code>agent_id</code> 的记忆内容，或在不启动完整 <code>src/lab</code> 的情况下验证 memory_bench 的功能。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">just</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory-chat-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xnne</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> congyin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 聪音</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8080</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">just</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory-chat-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xnne</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> elaina</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 伊蕾娜</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8081</span></span></code></pre></div><p>主链路（elaina VTuber / congyin /memory/chat）不经过 chat_server，而是通过 AgentCore + MemoryPlugin 直接调用 <code>/memory/search</code> 和 <code>/memory/add</code>。</p><hr><h2 id="📁-代码结构" tabindex="-1">📁 代码结构 <a class="header-anchor" href="#📁-代码结构" aria-label="Permalink to &quot;📁 代码结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>memory_bench/server/</span></span>
<span class="line"><span>├── chat_server.py          # 独立调试工具（CLI + REPL，非主链路）</span></span>
<span class="line"><span>├── chat_cli.py             # REPL 实现</span></span>
<span class="line"><span>├── startup.py              # 初始化逻辑（mem0 / OpenAI / 图谱管线）</span></span>
<span class="line"><span>├── router.py               # FastAPI 路由（/search、/add、/health）</span></span>
<span class="line"><span>├── claim_extractor.py      # LLM Claim 提取</span></span>
<span class="line"><span>├── neo4j_queries.py        # Cypher 语句模板与写入逻辑</span></span>
<span class="line"><span>└── conversation_store.py   # 对话持久化（chat_server 用）</span></span></code></pre></div><hr><h2 id="📚-延伸阅读" tabindex="-1">📚 延伸阅读 <a class="header-anchor" href="#📚-延伸阅读" aria-label="Permalink to &quot;📚 延伸阅读&quot;">​</a></h2><ul><li><a href="./routes.html">路由与端点</a> — API 文档</li></ul>`,42)])])}const g=s(i,[["render",t]]);export{m as __pageData,g as default};
